import React from 'react';

function user(props){
    const {isLoggedIn} = props;
    return (
        <div className="user-card position-absolute top-50 start-0 p-4" hidden={isLoggedIn === true}>
            <div className="user-card-sidebar">
                <ul className="user-settings">
                    <li className="user-settings-item"></li>
                </ul>
            </div>
            <div className="user-card-container">
                <i className="bi bi-person"> </i>
                <h1>USER</h1>
            </div>
        </div>
    );
}

export default user;
